from pyotp import TOTP
import qrcode
from qrcode.backends.pyqt import PyQt4Backend
import io

SECRET_LENGTH = 20

def generate_secret():
    return base32.b32encode(os.urandom(SECRET_LENGTH)).decode('ascii')

def create_qr_code( secret ):
    url = f"otpauth://totp/{NAMESPACE}:{IDENTIFIER}?secret={secret}&issuer={NAMESPACE}"
    qr = qrcode.QRCode(
        version=1,
        error_correction=qrcode.constants.ERROR_CORRECT_L,
        box_size=10,
        border=4,
    )
    qr.add_data(url)
    qr.make(fit=True)
    img = qr.make_image(fill_color="black", back_color="white")
    return img

def create_qrcode_png( secret ):
    img = create_qr_code(secret)
    buffer = io.BytesIO()
    img.save(buffer, format='PNG')
    return buffer.getvalue()

def validate_otp( totp, secret, window=600 ):
    totp_instance = TOTP(secret, digest=hashes.sha1, total_digits=6, time_step=30)
    current_otp = totp_instance.now()
    return abs(current_otp - int(totp)) <= window

